"./privacy/privacy.js": function(exports, __require__) {
const auditLog = exports.auditLog = [];

const maskName = exports.maskName = (name = "") =>
  String(name)
    .split(/\s+/)
    .filter(Boolean)
    .map((part) => `${part[0] || ""}${"*".repeat(Math.max(part.length - 1, 3))}`)
    .join(" ");

const maskPhone = exports.maskPhone = (phone = "") => {
  const value = String(phone);
  const prefix = value.startsWith("+") ? value.slice(0, 4) : "";
  return `${prefix}${prefix ? " " : ""}${"*".repeat(Math.max(value.replace(/\D/g, "").length - prefix.replace(/\D/g, "").length, 8))}`;
};

const logSensitiveReveal = exports.logSensitiveReveal = ({ field, value }) => {
  auditLog.unshift({
    id: `audit-${Date.now()}`,
    action: "sensitive-data-reveal",
    field,
    value,
    timestamp: new Date().toISOString(),
  });
};

},
